                       "  APPEND := map ap to map x,y to if empty?(x) then y else cons(first(x), ap(rest(x), y));" +
                       "       l := cons(1,cons(2,cons(3,empty)));" +
                       "in (Y(APPEND))(l,l) ";
        allCheck("[3.00] yappend", output, input );

      } catch (Exception e) {
        e.printStackTrace();
        fail("[3.00] yappend threw " + e);
