+import junit.framework.TestCase;
+import java.io.*;
+
+public class EvaluationTest extends TestCase {
+  public EvaluationTest(String name) { super(name); }
+
+  private void valueCheck(String answer, String program) {
+    Interpreter interp = new Interpreter(new StringReader(program));
+    assertEquals("CBV: " + program, answer, interp.callByValue().toString());
+  }
+
+  private void nameCheck(String answer, String program) {
+    Interpreter interp = new Interpreter(new StringReader(program));
+    assertEquals("CBN: " + program, answer, interp.callByName().toString());
+  }
+
+  private void needCheck(String answer, String program) {
+    Interpreter interp = new Interpreter(new StringReader(program));
+    assertEquals("CBNE: " + program, answer, interp.callByNeed().toString());
+  }
+
+  private void allCheck(String answer, String program) {
+    valueCheck(answer, program);
+    nameCheck(answer, program);
+    needCheck(answer, program);
+  }
+
+  public void testCbvCbnDifference() {
+    String program = "(map x, y to x)(1, 1 / 0)";
+    
+    // CBV should throw EvalException
+    try {
+      new Interpreter(new StringReader(program)).callByValue();
+      fail("CBV should have thrown EvalException for division by zero");
+    } catch (EvalException e) {
+      // Expected
+    }
+
+    // CBN and CBNE should succeed
+    nameCheck("1", program);
+    needCheck("1", program);
+  }
+
+  public void testClosureEquality() {
+    String program = "let m := (map x to x); in m = m";
+    
+    valueCheck("true", program);
+    nameCheck("false", program);
+    needCheck("true", program);
+  }
+
+  public void testShortCircuit() {
+    String pAnd = "false & (1 / 0 = 0)";
+    String pOr = "true | (1 / 0 = 0)";
+    
+    allCheck("false", pAnd);
+    allCheck("true", pOr);
+  }
+
+  public void testArity() {
+    allCheck("2", "arity(cons)");
+    allCheck("1", "arity(first)");
+    allCheck("1", "arity(arity)");
+    allCheck("0", "arity(map to 5)");
+    allCheck("3", "arity(map x, y, z to x)");
+    
+    try {
+      new Interpreter(new StringReader("arity(5)")).callByValue();
+      fail("arity(5) should throw EvalException");
+    } catch (EvalException e) {
+      // Expected
+    }
+  }
+
+  public void testListOperations() {
+    allCheck("(1 2)", "cons(1, cons(2, empty))");
+    allCheck("1", "first(cons(1, empty))");
+    allCheck("()", "rest(cons(1, empty))");
+    
+    try {
+      new Interpreter(new StringReader("first(empty)")).callByValue();
+      fail("first(empty) should throw EvalException");
+    } catch (EvalException e) {
+      // Expected
+    }
+    
+    try {
+      new Interpreter(new StringReader("rest(empty)")).callByValue();
+      fail("rest(empty) should throw EvalException");
+    } catch (EvalException e) {
+      // Expected
+    }
+
+    try {
+      new Interpreter(new StringReader("cons(1, 2)")).callByValue();
+      fail("cons(1, 2) should throw EvalException");
+    } catch (EvalException e) {
+      // Expected
+    }
+  }
+
+  public void testIf() {
+    allCheck("1", "if true then 1 else 2");
+    allCheck("2", "if false then 1 else 2");
+    
+    try {
+      new Interpreter(new StringReader("if 1 then 2 else 3")).callByValue();
+      fail("if 1 should throw EvalException");
+    } catch (EvalException e) {
+      // Expected
+    }
+  }
+
+  public void testArityMismatch() {
+    try {
+      new Interpreter(new StringReader("(map x to x)(1, 2)")).callByValue();
+      fail("Arity mismatch should throw EvalException");
+    } catch (EvalException e) {
+      // Expected
+    }
+  }
+
+  public void testPredicates() {
+    allCheck("true", "number?(5)");
+    allCheck("false", "number?(true)");
+    allCheck("true", "function?(map x to x)");
+    allCheck("true", "function?(cons)");
+    allCheck("true", "list?(cons(1, empty))");
+    allCheck("true", "list?(empty)");
+    allCheck("false", "list?(5)");
+    allCheck("true", "cons?(cons(1, empty))");
+    allCheck("false", "cons?(empty)");
+    allCheck("true", "empty?(empty)");
+    allCheck("false", "empty?(cons(1, empty))");
+  }
+
+  public void testEquality() {
+    allCheck("true", "5 = 5");
+    allCheck("false", "5 = 6");
+    allCheck("true", "true = true");
+    allCheck("false", "true = false");
+    allCheck("true", "empty = empty");
+    allCheck("true", "cons(1, empty) = cons(1, empty)");
+    allCheck("false", "cons(1, empty) = cons(2, empty)");
+    allCheck("false", "cons(1, empty) = empty");
+    allCheck("true", "cons(cons(1, empty), empty) = cons(cons(1, empty), empty)");
+  }
+
+  public void testComplexExpressions() {
+    allCheck("15", "let x := 5; y := 10; in x + y");
+    allCheck("110", "let f := map x to x * x + 10; in f(10)");
+    allCheck("2", "let f := map x to map y to x + y; in (f(1))(1)");
+  }
+}
